{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-mixed-risk-reconnect-plus-pump-parameter-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕未连接的出口流股 cooler-outlet-81 与泵 pump-12 的直接诊断生成候选提案：一项为 cooler-outlet-81 增加下游连接占位，另一项为 pump-12 修正无效出口压力目标并补充效率参数占位。",
      "issues": [
        {
          "title": "cooler-outlet-81 缺少下游去向",
          "detail": "出口流股被直接诊断为未连接，且当前快照为 invalid_topology，因此仅适合提出局部连接占位而不臆造具体下游对象。",
          "citations": [
            "diag-1",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        },
        {
          "title": "pump-12 的出口压力目标低于入口压力，且效率参数超出推荐范围",
          "detail": "泵的 outlet_pressure_target_kpa=150 低于入口流股 feed-81 的 pressure_kpa=190；同时 efficiency_percent=108 被诊断为超出推荐范围，适合提出局部参数修正/占位。",
          "citations": [
            "diag-2",
            "diag-3",
            "flowdoc-unit-1",
            "flowdoc-stream-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 cooler-outlet-81 添加下游连接占位",
          "target": {
            "type": "stream",
            "id": "cooler-outlet-81"
          },
          "rationale": "直接诊断指出该流股没有下游 consumer 或 export sink。为避免凭空指定具体设备，建议仅添加待确认的连接占位，以恢复最基本的拓扑完整性讨论基础。由于涉及拓扑去向，风险较高。",
          "patch": {
            "connection_placeholder": {
              "stream_id": "cooler-outlet-81",
              "missing_end": "target",
              "allowed_target_kinds": [
                "unit",
                "export_sink"
              ],
              "note": "需要用户确认 Trim Cooler Outlet 的下游接收对象或导出端。"
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 pump-12 提出出口压力目标修正并补充效率占位",
          "target": {
            "type": "unit",
            "id": "pump-12"
          },
          "rationale": "泵出口压力目标目前低于已知入口压力，直接触发无效诊断；同时效率参数超出推荐范围。基于现有证据，仅建议把出口压力目标提高到高于入口压力的待确认值，并将效率改为推荐范围内的待确认值，而不替用户决定最终工艺设计点。",
          "patch": {
            "parameter_updates": {
              "outlet_pressure_target_kpa": {
                "operator": ">",
                "reference": {
                  "stream_id": "feed-81",
                  "parameter": "pressure_kpa",
                  "value": 190
                }
              }
            },
            "parameter_placeholders": {
              "outlet_pressure_target_kpa": {
                "kind": "numeric_min_exclusive",
                "min_exclusive": 190,
                "unit": "kPa",
                "reason": "必须高于入口压力以消除当前直接诊断。"
              },
              "efficiency_percent": {
                "kind": "recommended_range_value",
                "reason": "当前 108 超出推荐 operating range，需要用户确认一个推荐范围内的值。"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "diag-3",
            "flowdoc-unit-1",
            "flowdoc-stream-1"
          ]
        }
      ],
      "confidence": 0.89,
      "citations": [
        "diag-1",
        "diag-2",
        "diag-3",
        "flowdoc-stream-3",
        "flowdoc-unit-1",
        "flowdoc-stream-1",
        "snapshot-1"
      ]
    }
  ]
}
